import{_ as n,c as r,o as i,a1 as s}from"./chunks/framework.DILC4Csi.js";const p=JSON.parse('{"title":"Änderungsprotokoll: Versionshistorie | OpenSkills","description":"Sehen Sie die Versionshistorie von OpenSkills ein. Erfahren Sie mehr über neue Funktionen, Verbesserungen und Fehlerbehebungen in jeder Version, um Ihren Upgrade-Pfad zu planen.","frontmatter":{"title":"Änderungsprotokoll: Versionshistorie | OpenSkills","sidebarTitle":"Neueste Änderungen","subtitle":"Änderungsprotokoll: Versionshistorie","description":"Sehen Sie die Versionshistorie von OpenSkills ein. Erfahren Sie mehr über neue Funktionen, Verbesserungen und Fehlerbehebungen in jeder Version, um Ihren Upgrade-Pfad zu planen.","order":6},"headers":[],"relativePath":"de/numman-ali/openskills/changelog/index.md","filePath":"de/numman-ali/openskills/changelog/index.md"}'),t={name:"de/numman-ali/openskills/changelog/index.md"};function o(l,e,a,h,d,u){return i(),r("div",null,[...e[0]||(e[0]=[s('<h1 id="anderungsprotokoll" tabindex="-1">Änderungsprotokoll <a class="header-anchor" href="#anderungsprotokoll" aria-label="Permalink to &quot;Änderungsprotokoll&quot;">​</a></h1><p>Dieses Kapitel dokumentiert die Versionshistorie von OpenSkills und hilft Ihnen, die neuen Funktionen, Verbesserungen und Fehlerbehebungen jeder Version zu verstehen.</p><h2 id="inhalt-dieses-kapitels" tabindex="-1">Inhalt dieses Kapitels <a class="header-anchor" href="#inhalt-dieses-kapitels" aria-label="Permalink to &quot;Inhalt dieses Kapitels&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Seite</th><th>Beschreibung</th></tr></thead><tbody><tr><td><a href="./changelog/">Änderungsprotokoll</a></td><td>Vollständige Versionshistorie einschließlich neuer Funktionen, Verbesserungen, Fehlerbehebungen und Sicherheitsupdates</td></tr></tbody></table><h2 id="so-verwenden-sie-das-anderungsprotokoll" tabindex="-1">So verwenden Sie das Änderungsprotokoll <a class="header-anchor" href="#so-verwenden-sie-das-anderungsprotokoll" aria-label="Permalink to &quot;So verwenden Sie das Änderungsprotokoll&quot;">​</a></h2><p>Das Änderungsprotokoll ist in umgekehrter chronologischer Reihenfolge der Versionsnummern organisiert (neueste Version zuerst). Jede Version enthält folgende Kategorien:</p><ul><li><strong>Neue Funktionen</strong> - Neue hinzugefügte Funktionen und Befehle</li><li><strong>Verbesserungen</strong> - Optimierungen und Erweiterungen bestehender Funktionen</li><li><strong>Fehlerbehebungen</strong> - Behobene Bugs</li><li><strong>Sicherheit</strong> - Sicherheitsbezogene Verbesserungen</li></ul><div class="tip custom-block"><p class="custom-block-title">Upgrade-Empfehlung</p><p>Bevor Sie OpenSkills aktualisieren, empfiehlt es sich, das Änderungsprotokoll zu lesen, um die Versionsänderungen zu verstehen. Achten Sie besonders auf:</p><ul><li><strong>Breaking Changes</strong> (Breaking Changes)</li><li>Die Verwendung neuer Funktionen</li><li>Die Status der Behobenen Probleme</li></ul></div><h2 id="nachste-schritte" tabindex="-1">Nächste Schritte <a class="header-anchor" href="#nachste-schritte" aria-label="Permalink to &quot;Nächste Schritte&quot;">​</a></h2><ul><li>Sehen Sie die <a href="./../faq/faq/">Häufig gestellte Fragen</a>, um häufige Fragen bei der Nutzung zu klären</li><li>Haben Sie ein Problem? Sehen Sie <a href="./../faq/troubleshooting/">Fehlerbehebung</a> für Lösungen</li><li>Möchten Sie mehr erfahren? Sehen Sie die <a href="./../appendix/cli-api/">CLI-API-Referenz</a> für die vollständige Befehlsdokumentation</li></ul>',10)])])}const c=n(t,[["render",o]]);export{p as __pageData,c as default};
